951	ngx_int_t
952	ngx_send_lowat(ngx_connection_t *c, size_t lowat)
953	{
954	    int  sndlowat;
955	
956	#if (NGX_HAVE_LOWAT_EVENT)
957	
958	    if (ngx_event_flags & NGX_USE_KQUEUE_EVENT) {
959	        c->write->available = lowat;
960	        return NGX_OK;
961	    }
962	
963	#endif
964	
965	    if (lowat == 0 || c->sndlowat) {
966	        return NGX_OK;
967	    }
968	
969	    sndlowat = (int) lowat;
970	
971	    if (setsockopt(c->fd, SOL_SOCKET, SO_SNDLOWAT,
972	                   (const void *) &sndlowat, sizeof(int))
973	        == -1)
974	    {
975	        ngx_connection_error(c, ngx_socket_errno,
976	                             "setsockopt(SO_SNDLOWAT) failed");
977	        return NGX_ERROR;
978	    }
979	
980	    c->sndlowat = 1;
981	
982	    return NGX_OK;
983	}
