1288	static char *
1289	ngx_event_core_init_conf(ngx_cycle_t *cycle, void *conf)
1290	{
1291	    ngx_event_conf_t  *ecf = conf;
1292	
1293	#if (NGX_HAVE_EPOLL) && !(NGX_TEST_BUILD_EPOLL)
1294	    int                  fd;
1295	#endif
1296	    ngx_int_t            i;
1297	    ngx_module_t        *module;
1298	    ngx_event_module_t  *event_module;
1299	
1300	    module = NULL;
1301	
1302	#if (NGX_HAVE_EPOLL) && !(NGX_TEST_BUILD_EPOLL)
1303	
1304	    fd = epoll_create(100);
1305	
1306	    if (fd != -1) {
1307	        (void) close(fd);
1308	        module = &ngx_epoll_module;
1309	
1310	    } else if (ngx_errno != NGX_ENOSYS) {
1311	        module = &ngx_epoll_module;
1312	    }
1313	
1314	#endif
1315	
1316	#if (NGX_HAVE_DEVPOLL) && !(NGX_TEST_BUILD_DEVPOLL)
1317	
1318	    module = &ngx_devpoll_module;
