339	
340	    ngx_log_error(NGX_LOG_NOTICE, cycle->log, 0, "start worker processes");
341	
342	    for (i = 0; i < n; i++) {
343	
344	        ngx_spawn_process(cycle, ngx_worker_process_cycle,
345	                          (void *) (intptr_t) i, "worker process", type);
346	
347	        ngx_pass_open_channel(cycle);
348	    }
